from typing import List, Union, Optional


class ASTNode:
    def __init__(
        self,
        node_type: str,
        value: Optional[float] = None,
        op: Optional[str] = None,
        left: Optional["ASTNode"] = None,
        right: Optional["ASTNode"] = None,
        operand: Optional["ASTNode"] = None,
    ):
        self.type = node_type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

    def __repr__(self) -> str:
        if self.type == "number":
            return f"Number({self.value})"
        elif self.type == "binop":
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == "unary":
            return f"Unary({self.op}, {self.operand})"
        return f"ASTNode({self.type})"


from typing import List, Union


def parse(expression: str) -> ASTNode:
    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty input")

    result = parse_expression(tokens)
    if tokens:
        raise ValueError(f"Unexpected token: {tokens[0]}")
    return result


def tokenize(expression: str) -> List[str]:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c == " ":
            i += 1
            continue

        if c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            num_str = []
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                num_str.append(expression[i])
                i += 1
            tokens.append("".join(num_str))
        else:
            raise ValueError(f"Invalid character: {c}")

    return tokens


def parse_expression(tokens: List[str]) -> ASTNode:
    return parse_additive(tokens)


def parse_additive(tokens: List[str]) -> ASTNode:
    left = parse_multiplicative(tokens)

    while tokens and tokens[0] in ("+", "-"):
        op = tokens.pop(0)
        right = parse_multiplicative(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def parse_multiplicative(tokens: List[str]) -> ASTNode:
    left = parse_unary(tokens)

    while tokens and tokens[0] in ("*", "/"):
        op = tokens.pop(0)
        right = parse_unary(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def parse_unary(tokens: List[str]) -> ASTNode:
    if tokens and tokens[0] == "-":
        tokens.pop(0)
        operand = parse_primary(tokens)
        return ASTNode("unary", op="-", operand=operand)

    return parse_primary(tokens)


def parse_primary(tokens: List[str]) -> ASTNode:
    if not tokens:
        raise ValueError("Unexpected end of input")

    token = tokens[0]

    if token == "(":
        tokens.pop(0)
        expr = parse_expression(tokens)
        if not tokens or tokens[0] != ")":
            raise ValueError("Unmatched parenthesis")
        tokens.pop(0)
        return expr
    elif token.replace(".", "", 1).isdigit():
        tokens.pop(0)
        return ASTNode("number", value=float(token))
    else:
        raise ValueError(f"Unexpected token: {token}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val

    raise ValueError(f"Unknown node type: {node.type}")
